      // Wait for config to load before fetching overview (prevents using default config)
      analyticsStore
        .fetchAiAdoptionOverview({
          ...(filters.projects && filters.projects.length > 0 && { projects: filters.projects }),
          config: aiAdoptionConfig.data,
        })
